import React, { useEffect } from "react";
import { contactAPI } from "../api/api";
import { injectThemeVars } from "./utils/templateHelpers";

const STYLE_ID = "freelancerkit-template-styles";
const FONT_ID = "freelancerkit-template-font";
const css = `
.freelancerkit-root{background:var(--color-bg);color:var(--color-text);min-height:100vh;font-family:var(--font-main),"Plus Jakarta Sans",sans-serif}.freelancerkit-root *{box-sizing:border-box}.freelancerkit-shell{max-width:1200px;margin:0 auto;padding:26px 20px 40px;display:grid;grid-template-columns:280px 1fr;gap:20px}.freelancerkit-sidebar{position:sticky;top:24px;align-self:start;padding:22px;border-radius:28px;background:#0f172a;color:#f8fafc}.freelancerkit-mark{font-size:.78rem;letter-spacing:.22em;text-transform:uppercase;color:var(--color-accent)}.freelancerkit-name{font-size:2rem;line-height:.95;margin-top:16px;font-weight:800}.freelancerkit-title{margin-top:8px;color:var(--color-accent);font-weight:700}.freelancerkit-nav{display:grid;gap:10px;margin-top:24px}.freelancerkit-nav button{background:none;border:none;color:#f8fafc;text-align:left;font:inherit;cursor:pointer;opacity:.8;padding:0}.freelancerkit-main{display:grid;gap:18px}.freelancerkit-hero,.freelancerkit-card{background:#fff;border:1px solid rgba(15,23,42,.08);border-radius:28px;padding:24px;box-shadow:0 18px 40px rgba(15,23,42,.06)}.freelancerkit-hero{display:grid;grid-template-columns:1.15fr .85fr;gap:18px;align-items:center}.freelancerkit-kicker{font-size:.78rem;letter-spacing:.22em;text-transform:uppercase;color:#64748b}.freelancerkit-title-xl{font-size:clamp(2.8rem,6vw,5rem);line-height:.92;margin:.45rem 0 0;font-weight:800;color:#0f172a}.freelancerkit-actions{display:flex;gap:12px;flex-wrap:wrap;margin-top:20px}.freelancerkit-btn{padding:12px 16px;border-radius:999px;border:none;font-weight:700;cursor:pointer}.freelancerkit-btn.primary{background:var(--color-accent);color:#062033}.freelancerkit-btn.secondary{background:#e2e8f0;color:#0f172a}.freelancerkit-service-grid,.freelancerkit-project-grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:16px}.freelancerkit-service{border-radius:22px;padding:18px;background:#f8fafc;border:1px solid rgba(15,23,42,.08)}.freelancerkit-service h3{margin:0 0 8px}.freelancerkit-service p{margin:0;color:#475569;line-height:1.7}.freelancerkit-proof{display:grid;gap:14px}.freelancerkit-contact{display:grid;grid-template-columns:1fr 1fr;gap:16px}.freelancerkit-contact form{display:grid;gap:12px}.freelancerkit-contact input,.freelancerkit-contact textarea{width:100%;padding:13px 15px;border-radius:14px;border:1px solid rgba(15,23,42,.1);background:#fff;color:#0f172a;font:inherit}.freelancerkit-contact button{padding:12px 16px;border:none;border-radius:999px;background:#0f172a;color:#fff;font-weight:800;cursor:pointer}@media (max-width:980px){.freelancerkit-shell{grid-template-columns:1fr}.freelancerkit-sidebar{position:static}.freelancerkit-hero,.freelancerkit-service-grid,.freelancerkit-project-grid,.freelancerkit-contact{grid-template-columns:1fr}}
`;
function scrollToSection(id){const node=document.getElementById(id); if(node) node.scrollIntoView({behavior:"smooth",block:"start"});}
export default function FreelancerKitTemplate({ portfolio }) {
  const profile = portfolio?.profile || {};
  const sections = portfolio?.sections || {};
  const style = injectThemeVars(portfolio?.themeData || {});
  useEffect(() => { if (!document.getElementById(STYLE_ID)) { const s=document.createElement("style"); s.id=STYLE_ID; s.textContent=css; document.head.appendChild(s);} if (!document.getElementById(FONT_ID)) { const l=document.createElement("link"); l.id=FONT_ID; l.rel="stylesheet"; l.href="https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@500;700;800&display=swap"; document.head.appendChild(l);} }, []);
  const submitContact = async (event) => { event.preventDefault(); const form = new FormData(event.currentTarget); try { await contactAPI.submit({ resumeId: portfolio?.resumeId, senderName: form.get("senderName"), senderEmail: form.get("senderEmail"), senderPhone: form.get("senderPhone"), subject: form.get("subject"), message: form.get("message") }); event.currentTarget.reset(); } catch (error) { console.error(error); } };
  return <div className="freelancerkit-root" style={style}><div className="freelancerkit-shell"><aside className="freelancerkit-sidebar"><div className="freelancerkit-mark">Freelancer Kit</div><div className="freelancerkit-name">{profile.fullName || "Your Name"}</div><div className="freelancerkit-title">{profile.professionalTitle || portfolio?.title || "Freelancer"}</div><div className="freelancerkit-nav"><button type="button" onClick={() => scrollToSection("services")}>Services</button><button type="button" onClick={() => scrollToSection("projects")}>Projects</button><button type="button" onClick={() => scrollToSection("contact")}>Contact</button></div><div style={{ marginTop: 24, display: "grid", gap: 8, fontSize: 14, color: "rgba(248,250,252,.72)" }}>{profile.email ? <div>{profile.email}</div> : null}{profile.location ? <div>{profile.location}</div> : null}</div></aside><main className="freelancerkit-main"><section className="freelancerkit-hero"><div><div className="freelancerkit-kicker">Independent but premium</div><h1 className="freelancerkit-title-xl">Clear offers. Better proof. Easier hiring.</h1><p style={{ color: "#475569", lineHeight: 1.8 }}>{profile.bio || "A conversion-ready freelancer portfolio that combines warmth, clarity, and fast trust-building for clients."}</p><div className="freelancerkit-actions"><button type="button" className="freelancerkit-btn primary" onClick={() => scrollToSection("contact")}>Start a Project</button><button type="button" className="freelancerkit-btn secondary" onClick={() => scrollToSection("projects")}>See Work</button></div></div><div className="freelancerkit-proof">{["Fast onboarding","Clear pricing conversations","Premium client experience"].map((item) => <div key={item} className="freelancerkit-service"><h3>{item}</h3><p>Built for professionals who need their portfolio to feel friendly, credible, and commercially strong.</p></div>)}</div></section><section className="freelancerkit-card" id="services"><div className="freelancerkit-kicker">Services</div><div className="freelancerkit-service-grid" style={{ marginTop: 14 }}>{(sections.services || []).map((service, index) => <div className="freelancerkit-service" key={service.id || index}><h3>{service.title || service.serviceTitle}</h3><p>Strategy, execution, and polished delivery shaped around real client outcomes.</p></div>)}</div></section><section className="freelancerkit-card" id="projects"><div className="freelancerkit-kicker">Selected Projects</div><div className="freelancerkit-project-grid" style={{ marginTop: 14 }}>{(sections.projects || []).map((project, index) => <div className="freelancerkit-service" key={project.id || index}><h3>{project.title}</h3><p>{project.description || project.summary}</p></div>)}</div></section><section className="freelancerkit-card" id="contact"><div className="freelancerkit-kicker">Contact</div><div className="freelancerkit-contact" style={{ marginTop: 14 }}><div><h2 style={{ fontSize: "2.2rem", margin: "0 0 10px" }}>Let&apos;s make the next launch feel premium.</h2><p style={{ color: "#475569", lineHeight: 1.8 }}>{profile.email || "Tell me what you are building, the timeline, and where you need help."}</p></div><form onSubmit={submitContact}><input name="senderName" placeholder="Your name" required /><input name="senderEmail" type="email" placeholder="Your email" required /><input name="senderPhone" placeholder="Phone number" /><input name="subject" placeholder="Project type" required /><textarea name="message" rows="5" placeholder="Project details" required /><button type="submit">Send inquiry</button></form></div></section></main></div></div>;
}

